<?php
declare(strict_types=1);
use App\Core\Env;use App\Core\Database;use App\Services\EmailService;
require dirname(__DIR__).'/app/core/Env.php';Env::load(dirname(__DIR__).'/.env');
spl_autoload_register(function(string $class):void{$prefix='App\\';if(!str_starts_with($class,$prefix))return;$relative=substr($class,strlen($prefix));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$file=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($file))require $file;});
$composer=dirname(__DIR__).'/vendor/autoload.php';if(is_file($composer))require $composer;
$pdo=Database::connection();$days=[60,30,14,7,1];
foreach($days as $d){$q=$pdo->prepare("SELECT c.*,u.name,u.email FROM employee_certifications c JOIN users u ON u.id=c.user_id WHERE c.status='active' AND c.expires_date=DATE_ADD(CURDATE(),INTERVAL ? DAY) AND u.email IS NOT NULL");$q->execute([$d]);foreach($q->fetchAll() as $c){$check=$pdo->prepare("SELECT 1 FROM certification_alerts WHERE employee_certification_id=? AND alert_days=? AND delivery_channel='email'");$check->execute([$c['id'],$d]);if($check->fetchColumn())continue;$subject='Certification expires in '.$d.' day'.($d===1?'':'s');$body='<p>Hello '.htmlspecialchars($c['name']).',</p><p>Your <strong>'.htmlspecialchars($c['certification_name']).'</strong> certification expires on <strong>'.htmlspecialchars($c['expires_date']).'</strong>.</p><p>Please provide renewal documentation to the office.</p>';try{(new EmailService())->sendMail($c['email'],$subject,$body);$pdo->prepare("INSERT INTO certification_alerts(employee_certification_id,alert_days,delivery_channel) VALUES(?,?,'email')")->execute([$c['id'],$d]);echo "Sent alert for certification {$c['id']}\n";}catch(Throwable $e){fwrite(STDERR,"Certification {$c['id']}: {$e->getMessage()}\n");}}}
